import React, { useState } from 'react';

export default function App() {

	const questions = [
		{
			questionText: 'What is the capital of Britain',
			answerOptions: [
				{ answerText: 'New York', answerSymbol: 'A', isCorrect: false },
				{ answerText: 'London', answerSymbol: 'B', isCorrect: false },
				{ answerText: 'Paris', answerSymbol: 'C', isCorrect: true, isTrue: true },
				{ answerText: 'Dublin', answerSymbol: 'D', isCorrect: false },
			],
		},
		{
			questionText: 'Who is CEO of Tesla?',
			answerOptions: [
				{ answerText: 'Jeff Bezos', answerSymbol: 'A', isCorrect: false },
				{ answerText: 'Elon Musk', answerSymbol: 'B', isCorrect: true, isTrue: true },
				{ answerText: 'Bill Gates', answerSymbol: 'C', isCorrect: false },
				{ answerText: 'Tony Stark', answerSymbol: 'D', isCorrect: false },
			],
		},
		{
			questionText: 'The iPhone was created by which company?',
			answerOptions: [
				{ answerText: 'Apple', answerSymbol: 'A', isCorrect: true, isTrue: true },
				{ answerText: 'Intel', answerSymbol: 'B', isCorrect: false },
				{ answerText: 'Amazon', answerSymbol: 'C', isCorrect: false },
				{ answerText: 'Microsoft', answerSymbol: 'D', isCorrect: false },
			],
		},
		{
			questionText: 'How many Harry Potter books are there?',
			answerOptions: [
				{ answerText: '1', answerSymbol: 'A', isCorrect: false },
				{ answerText: '4', answerSymbol: 'B', isCorrect: false },
				{ answerText: '6', answerSymbol: 'C', isCorrect: false },
				{ answerText: '7', answerSymbol: 'D', isCorrect: true, isTrue: true },
			],
		},
	];

	let [currentQuestion, setCurrentQuestion] = useState(0);
	const [showScore, setShowScore] = useState(false);
	const [score, setScore] = useState(0);
	const [startTest, setStartTest] = useState(true);


	const handleAnswerOptionClick = (isCorrect) => {
			  if (isCorrect) {
			  setScore(score * 2 || 500);   
		  }

	const nextQuestion = currentQuestion + 1;
		if (isCorrect && nextQuestion < questions.length) {
			setCurrentQuestion(nextQuestion);	
		}

		else {
			setShowScore(true);
			setStartTest(true);
		}
	};

	const handleStartTest = () => {
		setCurrentQuestion(0);
		setStartTest(false);
		setShowScore(false);
	}

	return (
		  <div className='app'>
			{
			  startTest ? (
				<div className='first-screen'>
					<div className='first-wrap'>
						<div className='hand'>
						</div>
						<div class="content">
					<h1>Who wants to be a millionaire?</h1>
				  <button onClick={handleStartTest} className='start-button'>Start</button></div></div>
				  {showScore  && (
					<div className='score-section'>
						<div className='hand'>
						</div>
						<div className='total-content'>
					  <p className="total">Total score: </p>
					  <span className="score">${score} earned</span>	
					  <button onClick={handleStartTest} className='start-button'>Try again</button>
					  </div>
					</div>
				  )}
				</div>
			  ) : (
				<div className='container'>
				  <div className='quez-section'>
					<div className='question-section'>
					  <div className='question-text'>{questions[currentQuestion].questionText}</div>
					</div>
					<div className='answer-section'>
					  {questions[currentQuestion].answerOptions.map((answerOption) => (
						<button className="button-answer" onClick={() => handleAnswerOptionClick(answerOption.isCorrect)}><span class="orange">{answerOption.answerSymbol}</span>{answerOption.answerText}</button>
					  ))}
					</div>
					<nav class="nav">
						<input class="nav__check" type="checkbox" id="showmenu"/>
						<label class="nav__showmenu" for="showmenu"></label>
						<ul clasNames="menu">
							<div class="wrap">$1,000,000</div>
							<div class="wrap">$500,000</div>
							<div class="wrap">$250,000</div>
							<div class="wrap">$125,000</div>
							<div class="wrap">$64,000</div>
							<div class="wrap">$32,000</div>
							<div class="wrap">$16,000</div>
							<div class="wrap">$8,000</div>
							<div class="wrap">$4,000</div>
							<div class="wrap">$2,000</div>
							<div class="wrap">$1,000</div>
							<div class="wrap">$500</div>
							<div class="wrap"><div className='question-count'>{score}</div></div>
  						</ul>
					</nav>
				  </div>
					<div className='right'>
						<div class="wrap">$1,000,000</div>
						<div class="wrap">$500,000</div>
						<div class="wrap">$250,000</div>
						<div class="wrap">$125,000</div>
						<div class="wrap">$64,000</div>
						<div class="wrap">$32,000</div>
						<div class="wrap">$16,000</div>
						<div class="wrap">$8,000</div>
						<div class="wrap">$4,000</div>
						<div class="wrap">$2,000</div>
						<div class="wrap">$1,000</div>
						<div class="wrap">$500</div>
						<div class="wrap wrap-orange"><div className='question-count'>${score}</div></div>
					</div>
				  </div>
				  )}
			  </div>
			  );
		}
